//! A script to print the program verification key.
//!
//! You can run this script using the following command:
//! ```shell
//! RUST_LOG=info cargo run --bin vkey --release
//! ```

use sp1_sdk::{Elf, HashableKey, Prover, ProverClient, ProvingKey};

/// The ELF (executable and linkable format) file for the Succinct RISC-V zkVM.
///
/// This file is generated by running `cargo prove build` inside the `program` directory.
pub const STATELESS_VERIFIER_ELF: &[u8] = include_bytes!("../../client/elf/verifier-client");

#[tokio::main]
async fn main() {
    // Setup the logger.
    sp1_sdk::utils::setup_logger();

    // Setup the prover client.
    std::env::set_var("SP1_PROVER", "cpu");
    let client = ProverClient::from_env().await;

    // Setup the program.
    let pk = client.setup(Elf::Static(STATELESS_VERIFIER_ELF)).await.unwrap();

    // Print the verification key.
    println!("Program Verification Key: {}", pk.verifying_key().bytes32());
}
